def _validate_repo_relative_path(path: str, *, field: str) -> str:
    cleaned = path.strip()
    if not cleaned:
        raise ValueError(f"{field} is required")
    if (
        cleaned.startswith("/")
        or cleaned.startswith("..")
        or cleaned == ".."
        or "/../" in cleaned
    ):
        raise ValueError(f"{field} must be a repo-relative path")
    return cleaned


